dhcpv6-ldra-profile.options:
            ${interface\-id}
            ${interface\-id\-syntax}
         <#if remote\-id?has_content && remote\-id\-syntax?has_content>
			${remote\-id}
        ${remote\-id\-syntax}
	<#elseif remote\-id?has_content>
			${remote\-id}
	</#if>
        <#if enterprise\-number?has_content>
            ${enterprise\-number}
        </#if>
	<#if vendor\-specific\-information?has_content>
            ${vendor\-specific\-information}
	</#if>
	<#if vendor\-specific\-information?has_content && access\-loop\-characteristics?has_content>
	    ${access\-loop\-characteristics}
	</#if>
         <#if start\-numbering\-from\-zero?has_content>
            ${start\-numbering\-from\-zero}
	</#if>
         <#if use\-leading\-zero?has_content>
            ${use\-leading\-zero}
	</#if>
